'use client';

import { useRef } from 'react';
import { orbVars, type OrbProps } from '../../lib/orb-state';
import { useOrbLevel } from '../../lib/use-orb-level';
import styles from './glass-orb.module.css';

export const GlassOrb = ({
  state = 'idle',
  size = 160,
  speed = 1,
  colorFrom,
  colorTo,
  levelRef,
  label = 'Assistant orb',
  className,
}: OrbProps) => {
  const ref = useRef<HTMLDivElement>(null);
  useOrbLevel(ref, state, levelRef);

  return (
    <div
      ref={ref}
      role="img"
      aria-label={label}
      data-state={state}
      className={[styles.orb, className].filter(Boolean).join(' ')}
      style={orbVars({ size, speed, colorFrom, colorTo })}
    >
      <span className={styles.aura} />
      <span className={styles.counter} />
      <span className={styles.sphere} />
      <span className={styles.highlight} />
    </div>
  );
};

.orb {
  --orb-size: 160px;
  --orb-speed: 1;
  --orb-color-from: #a78bfa;
  --orb-color-to: #38bdf8;
  --orb-level: 0;
  position: relative;
  display: grid;
  place-items: center;
  width: var(--orb-size);
  height: var(--orb-size);
  isolation: isolate;
}

.aura {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  background: conic-gradient(
    from 0deg,
    var(--orb-color-from),
    var(--orb-color-to),
    color-mix(in oklab, var(--orb-color-from), #fff 20%),
    var(--orb-color-from)
  );
  filter: blur(calc(10px + 10px * var(--orb-level)));
  opacity: calc(0.7 + 0.3 * var(--orb-level));
  transform: scale(calc(1 + 0.08 * var(--orb-level)));
  animation: orb-spin calc(8s / var(--orb-speed)) linear infinite;
}

.counter {
  position: absolute;
  width: 78%;
  height: 78%;
  border-radius: 50%;
  background: conic-gradient(
    from 180deg,
    transparent,
    color-mix(in oklab, var(--orb-color-to), transparent 30%),
    transparent
  );
  filter: blur(6px);
  opacity: 0;
  animation: orb-spin calc(5s / var(--orb-speed)) linear infinite reverse;
}

.orb[data-state='connecting'] .counter,
.orb[data-state='thinking'] .counter {
  opacity: 0.9;
}

.sphere {
  position: absolute;
  width: 80%;
  height: 80%;
  border-radius: 50%;
  background:
    radial-gradient(circle at 32% 28%, rgba(255, 255, 255, 0.55), transparent 42%),
    radial-gradient(circle at 70% 75%, color-mix(in oklab, var(--orb-color-to), transparent 35%), transparent 55%),
    rgba(255, 255, 255, 0.04);
  backdrop-filter: blur(6px);
  border: 1px solid rgba(255, 255, 255, 0.25);
  box-shadow:
    inset 0 2px 12px rgba(255, 255, 255, 0.35),
    inset 0 -10px 24px color-mix(in oklab, var(--orb-color-from), transparent 60%),
    0 8px 30px color-mix(in oklab, var(--orb-color-from), transparent 55%);
  transform: scale(calc(1 + 0.05 * var(--orb-level)));
  transition: transform 0.1s linear;
}

.highlight {
  position: absolute;
  top: 22%;
  left: 26%;
  width: 26%;
  height: 18%;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.9), transparent 70%);
  filter: blur(2px);
}

.orb[data-state='error'] {
  --orb-color-from: #fb7185;
  --orb-color-to: #f43f5e;
}

.orb[data-state='disabled'] {
  filter: grayscale(0.85);
  opacity: 0.5;
}

.orb[data-state='disabled'] .aura {
  animation: none;
}

@keyframes orb-spin {
  to {
    transform: rotate(360deg);
  }
}

@media (prefers-reduced-motion: reduce) {
  .aura,
  .counter {
    animation: none;
  }
}

'use client';

import { useRef } from 'react';
import clsx from 'clsx';
import { orbVars, type OrbProps } from '../../lib/orb-state';
import { useOrbLevel } from '../../lib/use-orb-level';

export const GlassOrbTw = ({
  state = 'idle',
  size = 160,
  speed = 1,
  colorFrom = '#a78bfa',
  colorTo = '#38bdf8',
  levelRef,
  label = 'Assistant orb',
  className,
}: OrbProps) => {
  const ref = useRef<HTMLDivElement>(null);
  useOrbLevel(ref, state, levelRef);
  const showCounter = state === 'connecting' || state === 'thinking';

  return (
    <div
      ref={ref}
      role="img"
      aria-label={label}
      className={clsx('relative grid place-items-center isolate', className)}
      style={{ ...orbVars({ size, speed, colorFrom, colorTo }), width: size, height: size }}
    >
      <span
        className="absolute h-full w-full rounded-full animate-orb-spin"
        style={{
          background: `conic-gradient(from 0deg, ${colorFrom}, ${colorTo}, color-mix(in oklab, ${colorFrom}, #fff 20%), ${colorFrom})`,
          filter: 'blur(calc(10px + 10px * var(--orb-level)))',
          opacity: 'calc(0.7 + 0.3 * var(--orb-level))',
          animationDuration: 'calc(8s / var(--orb-speed))',
        }}
      />
      {showCounter && (
        <span
          className="absolute h-[78%] w-[78%] rounded-full animate-orb-spin [animation-direction:reverse]"
          style={{
            background: `conic-gradient(from 180deg, transparent, color-mix(in oklab, ${colorTo}, transparent 30%), transparent)`,
            filter: 'blur(6px)',
            animationDuration: 'calc(5s / var(--orb-speed))',
          }}
        />
      )}
      <span
        className="absolute h-[80%] w-[80%] rounded-full border border-white/25 backdrop-blur-[6px] transition-transform duration-100"
        style={{
          background: `radial-gradient(circle at 32% 28%, rgba(255,255,255,0.55), transparent 42%), radial-gradient(circle at 70% 75%, color-mix(in oklab, ${colorTo}, transparent 35%), transparent 55%), rgba(255,255,255,0.04)`,
          boxShadow: `inset 0 2px 12px rgba(255,255,255,0.35), inset 0 -10px 24px color-mix(in oklab, ${colorFrom}, transparent 60%), 0 8px 30px color-mix(in oklab, ${colorFrom}, transparent 55%)`,
          transform: 'scale(calc(1 + 0.05 * var(--orb-level)))',
        }}
      />
      <span
        className="absolute top-[22%] left-[26%] h-[18%] w-[26%] rounded-full blur-[2px]"
        style={{ background: 'radial-gradient(circle, rgba(255,255,255,0.9), transparent 70%)' }}
      />
    </div>
  );
};
